
.cg-layout {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.section-head {
  font-family: var(--font-display);
  font-size: 0.9rem;
  letter-spacing: 0.1em;
  border-bottom: 2px solid var(--c-crimson);
  padding-bottom: 4px;
  display: inline-block;
  margin-bottom: 4px;
}

.head-icon {
  font-size: 0.75rem;
}

.cg-progress {
  font-size: 0.7rem;
  color: var(--c-ash);
  font-family: var(--font-mono);
}

.cg-progress-track {
  height: 4px;
  border: 1px solid var(--c-silver);
  background: #f0ecef;
  margin-top: 3px;
}

.cg-progress-fill {
  height: 100%;
  background: var(--c-gold);
  transition: width 0.3s ease;
}

.cg-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 7px;
}

.cg-card {
  border: 1.5px solid var(--c-silver);
  padding: 7px;
  background: #fff;
  display: flex;
  align-items: center;
  gap: 7px;
  opacity: 0.55;
  transition: all 0.25s;
}

.cg-card.unlocked {
  opacity: 1;
  border-color: var(--c-gold);
  background: linear-gradient(135deg, #fff, #fef9ee);
  box-shadow: 2px 2px 0 rgba(184, 134, 11, 0.2);
}

.cg-icon {
  font-size: 1.2rem;
  width: 28px;
  text-align: center;
  flex-shrink: 0;
}

.cg-info {
  flex: 1;
  min-width: 0;
}

.cg-name {
  font-weight: bold;
  font-size: 0.76rem;
  font-family: var(--font-display);
  display: block;
}

.cg-desc {
  font-size: 0.62rem;
  color: var(--c-ash);
  line-height: 1.3;
}

.cg-badge {
  font-size: 0.65rem;
  font-weight: bold;
  width: 18px;
  text-align: center;
  flex-shrink: 0;
}

.cg-badge.unlocked { color: var(--c-gold); }
.cg-badge.locked { color: var(--c-silver); }

@media (max-width: 600px) {
  .cg-grid {
    grid-template-columns: 1fr;
  }
}
