
.relation-layout {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.section-head {
  font-family: var(--font-display);
  font-size: 0.9rem;
  letter-spacing: 0.1em;
  border-bottom: 2px solid var(--c-gold);
  padding-bottom: 4px;
  display: inline-block;
  margin-bottom: 4px;
}

.head-icon {
  font-size: 0.75rem;
}

.relation-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 8px;
}

.relation-card {
  border: 1.5px solid var(--c-silver);
  padding: 8px;
  background: #fff;
  box-shadow: 2px 2px 0 rgba(45, 27, 78, 0.06);
  transition: transform 0.2s;
}

.relation-card:hover {
  transform: translateY(-1px);
  box-shadow: 3px 3px 0 rgba(45, 27, 78, 0.1);
}

.relation-top {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-bottom: 4px;
}

.relation-avatar {
  font-size: 1.1rem;
  width: 24px;
  text-align: center;
}

.relation-info {
  flex: 1;
  min-width: 0;
}

.relation-name {
  font-weight: bold;
  font-size: 0.82rem;
  font-family: var(--font-display);
  display: block;
}

.relation-role {
  font-size: 0.6rem;
  color: var(--c-ash);
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.relation-value {
  font-weight: bold;
  font-size: 0.9rem;
  font-family: var(--font-mono);
}

.relation-value.cold { color: var(--bar-pure); }
.relation-value.cool { color: var(--bar-curious); }
.relation-value.warm { color: var(--c-gold); }
.relation-value.hot { color: var(--c-crimson); }
.relation-value.deep { color: #ff2222; }

.relation-track {
  height: 5px;
  border: 1px solid var(--c-silver);
  background: #f0ecef;
  margin-bottom: 2px;
  position: relative;
}

.relation-fill {
  position: absolute;
  left: 0;
  top: 0;
  bottom: 0;
  transition: width 0.3s ease;
}

.relation-level {
  font-size: 0.6rem;
  text-align: right;
  color: var(--c-ash);
  font-family: var(--font-display);
  letter-spacing: 0.05em;
}

@media (max-width: 600px) {
  .relation-grid {
    grid-template-columns: 1fr;
  }
}
