
.corruption-section {
  padding: 10px;
  border-bottom: 2px dashed var(--c-silver);
  background: rgba(45, 27, 78, 0.02);
}

.section-head {
  text-align: center;
  font-family: var(--font-display);
  font-size: 0.9rem;
  letter-spacing: 0.15em;
  margin-bottom: 10px;
  color: var(--c-obsidian);
}

.head-icon {
  color: var(--c-amethyst);
  font-size: 0.7rem;
}

.corruption-grid {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.corruption-item {
  background: #fff;
  border: 1.5px solid var(--c-silver);
  padding: 8px 10px;
  box-shadow: 2px 2px 0 rgba(45, 27, 78, 0.08);
}

.corruption-header {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 4px;
}

.corruption-label {
  font-weight: bold;
  font-size: 0.78rem;
  font-family: var(--font-display);
  letter-spacing: 0.05em;
  min-width: 60px;
}

.corruption-value {
  font-size: 0.85rem;
  font-weight: bold;
  font-family: var(--font-mono);
  min-width: 32px;
}

.corruption-tier {
  font-size: 0.65rem;
  padding: 1px 6px;
  border-radius: 2px;
  font-family: var(--font-display);
  letter-spacing: 0.1em;
}

.corruption-tier.pure { background: #e8ecf0; color: var(--bar-pure); }
.corruption-tier.curious { background: #e8e0f0; color: var(--bar-curious); }
.corruption-tier.waver { background: #f0e0e4; color: var(--bar-waver); }
.corruption-tier.fallen { background: #f0e0e0; color: var(--bar-fallen); }
.corruption-tier.sunk { background: #f0d0d0; color: var(--bar-sunk); font-weight: bold; }

.corruption-track {
  position: relative;
  height: 8px;
  border: 1px solid var(--c-silver);
  background: #f0ecef;
  margin-bottom: 3px;
}

.corruption-fill {
  position: absolute;
  left: 0;
  top: 0;
  bottom: 0;
  transition: width 0.4s ease;
}

.corruption-ticks {
  position: absolute;
  left: 0;
  top: 0;
  right: 0;
  bottom: 0;
}

.tick {
  position: absolute;
  top: 0;
  bottom: 0;
  width: 1px;
  background: rgba(45, 27, 78, 0.3);
}

.corruption-desc {
  font-size: 0.68rem;
  color: var(--c-ash);
  font-style: italic;
  text-align: right;
}

@media (max-width: 600px) {
  .corruption-header {
    flex-wrap: wrap;
  }
}
