
.experience-layout {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.section-head {
  font-family: var(--font-display);
  font-size: 0.9rem;
  letter-spacing: 0.1em;
  border-bottom: 2px solid var(--c-crimson);
  padding-bottom: 4px;
  display: inline-block;
  margin-bottom: 4px;
}

.head-icon {
  font-size: 0.75rem;
}

.section-subhead {
  font-size: 0.78rem;
  font-weight: bold;
  font-family: var(--font-display);
  color: var(--c-ash);
  letter-spacing: 0.05em;
}

.milestone-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 5px;
}

.milestone-item {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 5px 8px;
  border: 1px solid var(--c-silver);
  background: #fff;
  opacity: 0.45;
  transition: opacity 0.3s;
}

.milestone-item.achieved {
  opacity: 1;
  border-color: var(--c-crimson);
  background: linear-gradient(135deg, #fff, #fef5f5);
}

.milestone-icon {
  font-size: 0.75rem;
  width: 16px;
  text-align: center;
}

.milestone-item.achieved .milestone-icon {
  color: var(--c-crimson);
}

.milestone-name {
  font-size: 0.72rem;
  font-family: var(--font-display);
}

.stat-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 7px;
}

.stat-card {
  border: 1.5px solid var(--c-silver);
  padding: 8px 6px;
  background: #fff;
  text-align: center;
}

.stat-card.achieved {
  border-color: var(--c-crimson);
  background: linear-gradient(180deg, #fff, #fef5f5);
}

.stat-value {
  display: block;
  font-size: 1.4rem;
  font-weight: bold;
  font-family: var(--font-mono);
  color: var(--c-obsidian);
}

.stat-card.achieved .stat-value {
  color: var(--c-crimson);
}

.stat-label {
  display: block;
  font-size: 0.62rem;
  color: var(--c-ash);
  margin-top: 2px;
  letter-spacing: 0.05em;
}

@media (max-width: 600px) {
  .milestone-grid {
    grid-template-columns: 1fr;
  }
}
