
.body-layout {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.section-head {
  font-family: var(--font-display);
  font-size: 0.9rem;
  letter-spacing: 0.1em;
  border-bottom: 2px solid var(--c-amethyst);
  padding-bottom: 4px;
  display: inline-block;
  margin-bottom: 4px;
}

.head-icon {
  font-size: 0.75rem;
}

.section-subhead {
  font-size: 0.78rem;
  font-weight: bold;
  font-family: var(--font-display);
  color: var(--c-ash);
  letter-spacing: 0.05em;
}

.status-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 8px;
}

.status-card {
  border: 1.5px solid var(--c-silver);
  padding: 8px;
  background: #fff;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.status-label {
  font-size: 0.75rem;
  color: var(--c-ash);
  font-family: var(--font-display);
}

.status-value {
  font-weight: bold;
  font-size: 0.85rem;
  font-family: var(--font-mono);
}

.status-value.virgin { color: var(--bar-pure); }
.status-value.non-virgin { color: var(--c-crimson); }
.status-value.modified { color: #ff4444; }

.status-value.mod-0 { color: var(--c-ash); }
.status-value.mod-1 { color: var(--c-amethyst); }
.status-value.mod-2 { color: var(--c-crimson); }
.status-value.mod-3 { color: #ff2222; }

.sensitivity-list {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.sensitivity-item {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 4px 0;
  border-bottom: 1px dotted var(--c-silver);
}

.zone-name {
  font-size: 0.72rem;
  min-width: 55px;
  color: var(--c-obsidian);
  font-family: var(--font-display);
}

.zone-track {
  flex: 1;
  height: 6px;
  border: 1px solid var(--c-silver);
  background: #f0ecef;
  position: relative;
}

.zone-fill {
  position: absolute;
  left: 0;
  top: 0;
  bottom: 0;
  background: linear-gradient(90deg, var(--c-rose), var(--c-crimson));
  transition: width 0.3s ease;
}

.zone-value {
  font-size: 0.7rem;
  font-weight: bold;
  font-family: var(--font-mono);
  min-width: 24px;
  text-align: right;
  color: var(--c-ash);
}

.mod-detail {
  background: rgba(139, 26, 26, 0.08);
  border: 1px solid var(--c-crimson);
  padding: 8px;
  font-size: 0.72rem;
  color: var(--c-crimson);
  line-height: 1.5;
  display: flex;
  gap: 6px;
  align-items: flex-start;
}

@media (max-width: 600px) {
  .status-grid {
    grid-template-columns: 1fr;
  }
}
